async function boostHandle(r) {
  if (r.status === 401) {
    const { login } = useAuth()
    login()
    throw new Error('请先登录')
  }
  if (!r.ok) {
    let msg = `HTTP ${r.status}`
    try { const e = await r.json(); msg = e.message || e.error || msg } catch {}
    throw new Error(msg)
  }
  return r.json()
}

